**File:** `openssl/crypto/x509/pcy_tree.c `  
**Function:** `X509_policy_check`  
**Version:** OpenSSL `git-master`


### Description

In X509_policy_check(), the variable `tree` is initialized by `tree_init()` (line **670**).

When `init_ret` indicates both `X509_PCY_TREE_EXPLICIT` and `X509_PCY_TREE_EMPTY`, the function returns `X509_PCY_TREE_FAILURE` without freeing the previously allocated `tree`. As a result, the allocated `tree` object is leaked on this error path.

#### Vulnerable Code (lines **670-685**)

    init_ret = tree_init(&tree, certs, flags); // line 670: tree allocated here

    if (init_ret <= 0)
        return init_ret;

    if ((init_ret & X509_PCY_TREE_EXPLICIT) == 0) {
        if (init_ret & X509_PCY_TREE_EMPTY) {
            X509_policy_tree_free(tree);
            return X509_PCY_TREE_VALID;
        }
    } else {
        *pexplicit_policy = 1;
        /* Tree empty and requireExplicit True: Error */
        if (init_ret & X509_PCY_TREE_EMPTY)
            return X509_PCY_TREE_FAILURE;  // line 684: tree leaked here
    }

Here, `tree` is allocated by `tree_init(&tree, certs, flags)`, but in the explicit-and-empty case it is not freed before returning.

### Suggested Fix

Free `tree` before returning on this failure path, similar to the previous branch:

    } else {
        *pexplicit_policy = 1;
        /* Tree empty and requireExplicit True: Error */
        if (init_ret & X509_PCY_TREE_EMPTY) {
            X509_policy_tree_free(tree);
            return X509_PCY_TREE_FAILURE;
        }
    }

**File:** `openssl/ssl/quic/quic_port.c`  
**Function:** `port_make_channel`  
**Version:** OpenSSL `git-master`

### Description

In `port_make_channel()`, a `QUIC_CHANNEL` object is allocated using `ossl_quic_channel_alloc(&args)` (line **536**). On later failure paths, the function frees the channel using `OPENSSL_free(ch)` instead of the full destructor `ossl_quic_channel_free(ch)`.

As a result, resources owned by `ch` may leak. For example, if `ch->qlog_title` is successfully allocated using `OPENSSL_strdup()` and a later step fails, freeing only `ch` does not release `ch->qlog_title`. More generally, any resources owned by the partially initialized channel may be leaked.

#### Vulnerable Code
``` c
ch = ossl_quic_channel_alloc(&args); /* line 536: ch is allocated */
if (ch == NULL)
    return NULL;

...

if (ch->tls != NULL && ch->tls->ctx->qlog_title != NULL) {
    if ((ch->qlog_title = OPENSSL_strdup(ch->tls->ctx->qlog_title)) == NULL) {
        OPENSSL_free(ch);   /* line 566: only frees ch, not owned subobjects */
        return NULL;
    }
}

...

if (!ossl_quic_channel_init(ch)) {
    OPENSSL_free(ch);   /* line 576: only frees ch, not owned subobjects */
    return NULL;
}
```
#### Reference Code
``` c
void ossl_quic_channel_free(QUIC_CHANNEL *ch)
{
    if (ch == NULL)
        return;

    ch_cleanup(ch);
    OPENSSL_free(ch);
}
```
### Suggested Fix

Use `ossl_quic_channel_free(ch)` on these failure paths instead of `OPENSSL_free(ch)`.
``` c
if (ch->tls != NULL && ch->tls->ctx->qlog_title != NULL) {
    if ((ch->qlog_title = OPENSSL_strdup(ch->tls->ctx->qlog_title)) == NULL) {
        ossl_quic_channel_free(ch);
        return NULL;
    }
}

...

if (!ossl_quic_channel_init(ch)) {
    ossl_quic_channel_free(ch);
    return NULL;
}
```

**File:** `openssl/ssl/statem/statem_dtls.c`  
**Function:** `dtls1_buffer_message`  
**Version:** OpenSSL `git-master`

### Description

In `dtls1_buffer_message()`, a handshake fragment (`frag`) is allocated usin`dtls1_hm_fragment_new()` (line **1136**) and then wrapped in a `pitem` object created by `pitem_new()` (line **1174**).

The `pitem` is inserted into the retransmission queue using `pqueue_insert()`. However, `pqueue_insert()` may return `NULL` (e.g., when a duplicate priority is detected; see the reference code), and its return value is not checked in `dtls1_buffer_message()`.

If insertion fails, both the allocated `pitem` and the associated fragment (`frag`, stored in `item->data`) are leaked.

#### Vulnerable Code
``` c
frag = dtls1_hm_fragment_new(s->init_num, 0); /* line 1136: allocated */
if (frag == NULL)
    return 0;

...

item = pitem_new(seq64be, frag); /* line 1174: pitem created */
if (item == NULL) {
    dtls1_hm_fragment_free(frag);
    return 0;
}

pqueue_insert(s->d1->sent_messages, item); /* line 1180: return value ignored */
return 1;
```

#### Reference Code

`pqueue_insert()` may return `NULL` when insertion fails:
``` c
pitem *pqueue_insert(pqueue *pq, pitem *item)
{
    ...
    else if (cmp == 0) /* duplicates not allowed */
        return NULL;
    ...
}
```
### Suggested Fix

Check the return value of `pqueue_insert()` and free both the `pitem` and its associated fragment if insertion fails.
``` c
if (pqueue_insert(s->d1->sent_messages, item) == NULL) {
    dtls1_hm_fragment_free(frag);
    OPENSSL_free(item);
    return 0;
}

return 1;
```

