  ---->  InterlockedExchange((LONG volatile *)dst, val);
    return 1;
#endif
}

```

## Bug Description

In `crypto/x509/x509_vfy.c`, the `build_chain()` function calls `X509_self_signed()` at line 3234 but does not handle the `-1` (error) return value. The `> 0` comparison silently treats internal errors identically to "not self-signed", allowing `find_issuer()` to proceed on a certificate that should have been rejected.

```c
// Line 3234 — error return not handled
issuer = (X509_self_signed(curr, 0) > 0 || num > max_depth) ?
    NULL : find_issuer(ctx, sk_untrusted, curr);
```

`X509_self_signed()` returns:
- `1` = self-signed
- `0` = not self-signed
- `-1` = error (e.g., `X509_get0_pubkey()` returned NULL, `ossl_x509v3_cache_extensions()` failed)

The same function correctly handles this error earlier at line 3111-3116:

```c
// Line 3111-3116 — correct handling
int self_signed = X509_self_signed(curr, 0);
if (self_signed < 0) {
    X509_free(issuer);
    goto int_err;
}
```

## Impact

A crafted certificate that triggers an `ossl_x509v3_cache_extensions()` failure (e.g., via malformed extensions) will not terminate the untrusted-issuer search. The chain builder will call `find_issuer()` for it, potentially chaining it to another certificate, creating a chain that should not exist. This bypasses the self-signed loop-termination check.

## Affected Versions

Confirmed present in OpenSSL 3.0.13. The code pattern appears unchanged on master.

## Suggested Fix

Mirror the error handling from line 3111:

```c
int self_signed = X509_self_signed(curr, 0);
if (self_signed < 0)
    goto int_err;
issuer = (self_signed > 0 || num > max_depth) ?
    NULL : find_issuer(ctx, sk_untrusted, curr);
```

## Bug Description

`check_cert()` and `check_revocation()` in `crypto/x509/x509_vfy.c` return `0` for both "revocation check failed" and "internal error" (e.g., OOM, store lookup failure). Callers cannot distinguish the two cases, and the code itself acknowledges this with comments:

```c
// Line 907
/* Sadly, returns 0 also on internal error. */
static int check_revocation(X509_STORE_CTX *ctx)

// Line 931
/* Sadly, returns 0 also on internal error. */
static int check_cert(X509_STORE_CTX *ctx)
```

### Where the conflation happens

In `check_cert()`, multiple callees (`ctx->get_crl`, `get_crl_delta`, `ctx->check_crl`, `ctx->cert_crl`) can fail due to either a verification issue or an internal error (allocation failure, store lookup failure). All failures flow to `return ok` at line 1001 with `ok == 0`, regardless of cause.

The caller `check_revocation()` propagates this directly:

```c
// Line 924-926
ok = check_cert(ctx);
if (!ok)
    return ok;
```

And `verify_chain()` at line 221 checks `<= 0`:

```c
|| (ok = ctx->check_revocation(ctx)) <= 0)
    return ok;
```

Since `check_revocation` never returns `-1` for internal error (only `0` or `1`), `verify_chain` treats all failures as verification failures, never as internal errors warranting a `-1` return.

### Impact

- A **transient CRL store lookup failure** (network timeout, OOM during CRL fetch) is misreported to the application as a revocation verification failure rather than an internal error.
- Applications that distinguish `0` (verification failure) from `-1` (internal error) in `X509_verify_cert()` results — as the API contract suggests — will misclassify transient failures as permanent verification rejections.
- This can cause **unnecessary certificate rejection** during transient resource pressure, when the correct behavior would be to signal an internal error so the application can retry.

### Suggested Fix

Have `check_cert()` return `-1` on internal error paths (allocation failure, store lookup failure) and `0` only for actual verification failures. Update `check_revocation()` to propagate the `-1` to `verify_chain()`, which already handles negative returns correctly.

For example, in `check_cert()` around line 951-958:

```c
if (ctx->get_crl != NULL)
    ok = ctx->get_crl(ctx, &crl, x);
else
    ok = get_crl_delta(ctx, &crl, &dcrl, x);
if (!ok) {
    // If this is a lookup/allocation error vs "no CRL available",
    // return -1 instead of falling through with ok=0
    ok = verify_cb_crl(ctx, X509_V_ERR_UNABLE_TO_GET_CRL);
    goto done;
}
```

The `ctx->check_crl` and `ctx->cert_crl` callbacks would similarly need to distinguish their error returns.

### Affected Versions

Present in 3.0.13 and confirmed unchanged on current master. The "Sadly" comments suggest this has been a known issue for some time.

## Bug Description

In `check_trust()` in `crypto/x509/x509_vfy.c` (line 880), the return value of `sk_X509_set()` is explicitly discarded when replacing the leaf certificate in the chain with a trusted match from the trust store:

```c
// Line 879-882
/* Replace leaf with trusted match */
(void)sk_X509_set(ctx->chain, 0, mx);
X509_free(x);
ctx->num_untrusted = 0;
goto trusted;
```

`sk_X509_set()` returns `NULL` on failure (e.g., if the index is out of bounds). If it fails, the old leaf `x` is freed on line 881 but was never replaced in the chain — leaving `ctx->chain[0]` as a dangling pointer. The function then proceeds to `goto trusted`, and subsequent verification stages operate on a chain with a freed certificate at position 0.

### Why this matters

While `index == 0` on a non-empty chain should always be valid (making this currently safe in practice), the explicit `(void)` cast suppresses any future compiler or static-analysis warning. If the function were ever refactored such that the chain could be empty at this point, or if the index computation changed, this would become a use-after-free with no diagnostic.

The defensive fix is trivial: check the return value before freeing `x`.

### Suggested Fix

```c
/* Replace leaf with trusted match */
if (sk_X509_set(ctx->chain, 0, mx) == NULL) {
    X509_free(mx);
    return -1;
}
X509_free(x);
ctx->num_untrusted = 0;
goto trusted;
```

### Affected Versions

Present in 3.0.13 and confirmed unchanged on current master.

## Bug Description

In `crypto/x509/x509_vfy.c`, `check_issued()` (line 344) reduces the rich error code from `ossl_x509_likely_issued()` to a boolean, discarding the specific reason why issuer matching failed:

```c
static int check_issued(ossl_unused X509_STORE_CTX *ctx, X509 *x, X509 *issuer)
{
    int err = ossl_x509_likely_issued(issuer, x);

    if (err == X509_V_OK)
        return 1;
    /*
     * SUBJECT_ISSUER_MISMATCH just means 'x' is clearly not issued by 'issuer'.
     * Every other error code likely indicates a real error.
     */
    return 0;
}
```

`ossl_x509_likely_issued()` (in `v3_purp.c`) returns these distinct error codes:

- `X509_V_ERR_SUBJECT_ISSUER_MISMATCH` — normal, not a match
- `X509_V_ERR_AKID_SKID_MISMATCH` — subject matches but AKID/SKID don't
- `X509_V_ERR_AKID_ISSUER_SERIAL_MISMATCH` — AKID issuer/serial don't match
- `X509_V_ERR_KEYUSAGE_NO_CERTSIGN` — issuer lacks keyCertSign
- `X509_V_ERR_KEYUSAGE_NO_DIGITAL_SIGNATURE` — issuer lacks digitalSignature (for self-signed check)
- `X509_V_ERR_NO_ISSUER_PUBLIC_KEY` — issuer has no public key
- `X509_V_ERR_UNSUPPORTED_SIGNATURE_ALGORITHM` — unknown signature algorithm
- `X509_V_ERR_SIGNATURE_ALGORITHM_MISMATCH` — issuer/subject sig alg mismatch
- `X509_V_ERR_UNSPECIFIED` — internal error (extension caching failure)

The comment in the code acknowledges that "every other error code likely indicates a real error", yet they are all silently mapped to `0` (not issued). This means:

1. **AKID mismatches are invisible.** A certificate whose subject name matches but whose Authority Key Identifier doesn't match the issuer's Subject Key Identifier is silently skipped. When debugging chain-building failures, there is no indication that a candidate issuer was found by name but rejected by AKID — the issuer simply appears to not exist.

2. **Internal errors are swallowed.** `X509_V_ERR_UNSPECIFIED` (from `ossl_x509v3_cache_extensions` failure) and `X509_V_ERR_NO_ISSUER_PUBLIC_KEY` are treated identically to "subject doesn't match" rather than surfacing as errors.

3. **`find_issuer()` has no diagnostic path.** Since `check_issued` is called in a loop by `find_issuer()` (line 330), there is no mechanism to report *why* a candidate issuer was rejected. All rejections look the same.

### Impact

This primarily affects **debuggability**. Chain-building failures caused by AKID/SKID mismatches, missing issuer public keys, or signature algorithm mismatches produce no diagnostic output — the verification simply fails with "unable to find issuer" rather than identifying the specific mismatch. This makes it significantly harder to diagnose certificate deployment issues in production.

### Suggested Fix

At minimum, set `ctx->error` for non-`SUBJECT_ISSUER_MISMATCH` errors before returning, so that the diagnostic information is available even if the return value remains boolean:

```c
static int check_issued(ossl_unused X509_STORE_CTX *ctx, X509 *x, X509 *issuer)
{
    int err = ossl_x509_likely_issued(issuer, x);

    if (err == X509_V_OK)
        return 1;
    if (err != X509_V_ERR_SUBJECT_ISSUER_MISMATCH)
        ctx->error = err;
    return 0;
}
```

A more thorough fix would change the return type to propagate the error code, but that would require updating the `check_issued` callback signature.

### Affected Versions

Present in 3.0.13 and confirmed unchanged on current master (only `const` qualifiers added to parameters).

The FIPS provider's DH key exchange implementation (`providers/implementations/exchange/dh_exch.c`) calls the non-constant-time `DH_compute_key()` by default when performing plain DH derivation.

In `dh_plain_derive()` (line 167-170):
```c
if (pad)
    ret = DH_compute_key_padded(secret, pub_key, pdhctx->dh);
else
    ret = DH_compute_key(secret, pub_key, pdhctx->dh);
```

The `pad` field in `PROV_DH_CTX` defaults to 0 (via `OPENSSL_zalloc` in `dh_newctx`), so unless the caller explicitly sets `OSSL_EXCHANGE_PARAM_PAD` to 1, the non-padded path is taken.

`DH_compute_key()` in `crypto/dh/dh_key.c` strips leading zero bytes from the shared secret with key-dependent `memmove`/`memset` operations that the code itself acknowledges are timing-leaky:

```c
/* key-dependent memory access, potentially leaking npad / ret */
memmove(key, key + npad, ret);
/* key-dependent memory access, potentially leaking npad / ret */
memset(key + ret, 0, npad);
```

The number of leading zero bytes reveals information about the shared secret value, and the variable-length output leaks this through timing and memory access patterns.

The X9.42 KDF path (`dh_X9_42_kdf_derive`) always passes `pad=1`, so it is not affected. Only plain DH derivation via `EVP_PKEY_derive` without explicit padding configuration is affected.

### Suggested fix

In the FIPS provider, `dh_plain_derive` should always use `DH_compute_key_padded` regardless of the `pad` setting, or the default for `pad` should be 1 in FIPS mode:

```c
#ifdef FIPS_MODULE
    ret = DH_compute_key_padded(secret, pub_key, pdhctx->dh);
#else
    if (pad)
        ret = DH_compute_key_padded(secret, pub_key, pdhctx->dh);
    else
        ret = DH_compute_key(secret, pub_key, pdhctx->dh);
#endif
```

Alternatively, `DH_compute_key` itself could use constant-time operations for the leading-zero removal when compiled in FIPS mode.

### Affected versions

Present in 3.0.13, likely affects all 3.x branches since the provider architecture was introduced.

A 24-byte memory leak was found in OpenSSL versions 3.0.12 and 3.5.4, which can be reproduced using the following command.
It is suspected that the i2r_issuer_sign_tool interface did not release the original memory before assigning ist->signTool = ASN1_UTF8STRING_new();
```
static ISSUER_SIGN_TOOL *v2i_issuer_sign_tool(X509V3_EXT_METHOD *method, X509V3_CTX *ctx,
                        STACK_OF(CONF_VALUE) *nval)
{
    ISSUER_SIGN_TOOL *ist = ISSUER_SIGN_TOOL_new(); //Allocate memory
    int i;

    if (ist == NULL) {
        ERR_raise(ERR_LIB_X509V3, ERR_R_MALLOC_FAILURE);
        return NULL;
    }
    for (i = 0; i < sk_CONF_VALUE_num(nval); ++i) {
        CONF_VALUE *cnf = sk_CONF_VALUE_value(nval, i);

        if (cnf == NULL) {
            continue;
        }
        if (strcmp(cnf->name, "signTool") == 0) {
            ist->signTool = ASN1_UTF8STRING_new();  //Allocating memory again
            if (ist->signTool == NULL
                || cnf->value == NULL
                || !ASN1_STRING_set(ist->signTool, cnf->value, strlen(cnf->value))) {
                ERR_raise(ERR_LIB_X509V3, ERR_R_MALLOC_FAILURE);
                goto err;
            }
```


