 *
 * The ChaCha20_ctr32_vsx_8x function uses vxxlor to spill VMX values
 * into VSR0-26, which overlaps FPR0-FPR26. Per the ELFv2 ABI, FPR14-FPR31
 * are callee-saved, but the function never saves/restores them.
 *
 * The 8x path is only used on POWER10 hardware with buffers > 255 bytes.
 * On POWER9 or earlier (or non-PPC architectures), this test trivially passes.
 */

#include <openssl/evp.h>
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/* Use global buffers so they don't compete for registers in the test function */
static unsigned char chacha_key[32];
static unsigned char chacha_iv[16];
static unsigned char chacha_in[512];
static unsigned char chacha_out[512];

/*
 * noinline wrapper: prevents the compiler from seeing through the call
 * and potentially "helping" by saving/restoring registers around it.
 */
__attribute__((noinline))
static int do_chacha20(void)
{
    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
    int outlen, tmplen;

    if (!ctx)
        return 0;
    if (EVP_EncryptInit_ex(ctx, EVP_chacha20(), NULL,
                           chacha_key, chacha_iv) != 1)
        goto err;
    if (EVP_EncryptUpdate(ctx, chacha_out, &outlen,
                          chacha_in, sizeof(chacha_in)) != 1)
        goto err;
    if (EVP_EncryptFinal_ex(ctx, chacha_out + outlen, &tmplen) != 1)
        goto err;
    EVP_CIPHER_CTX_free(ctx);
    return 1;
err:
    EVP_CIPHER_CTX_free(ctx);
    return 0;
}

