--- KEY GENERATION FAILED ---
4037459D1D7F0000:error:08000081:elliptic curve routines:EC_GROUP_new_from_params:unknown group:../openssl/crypto/ec/ec_lib.c:1761:
```

```
#include <stdio.h>
#include <openssl/evp.h>
#include <openssl/ec.h>
#include <openssl/param_build.h>
#include <openssl/err.h>

void print_errors() {
    ERR_print_errors_fp(stderr);
}

int main() {
    // 1. Load a standard curve (BrainpoolP256r1 as used in the logs)
    int nid = NID_brainpoolP256r1;
    EC_GROUP *group = EC_GROUP_new_by_curve_name(nid);
    if (!group) {
        fprintf(stderr, "Failed to load standard curve\n");
        return 1;
    }

    // 2. Modify the generator (Simulating PACE Generic Mapping)
    // We create G_tilde by multiplying the original generator by 2.
    EC_POINT *G_tilde = EC_POINT_new(group);
    BIGNUM *scalar = BN_new();
    BN_set_word(scalar, 2);

    if (!EC_POINT_mul(group, G_tilde, scalar, NULL, NULL, NULL)) {
        fprintf(stderr, "Failed to calculate new generator G_tilde\n");
        return 1;
    }

    BIGNUM *order = BN_new();
    BIGNUM *cofactor = BN_new();
    EC_GROUP_get_order(group, order, NULL);
    EC_GROUP_get_cofactor(group, cofactor, NULL);

    // Update the group with the new generator
    if (!EC_GROUP_set_generator(group, G_tilde, order, cofactor)) {
        fprintf(stderr, "EC_GROUP_set_generator failed\n");
        return 1;
    }

    // 3. Extract parameters for OSSL_PARAM_BLD (Manual rebuild)
    BIGNUM *p = BN_new(), *a = BN_new(), *b = BN_new();
    EC_GROUP_get_curve(group, p, a, b, NULL);

    unsigned char gen_buf[256];
    size_t gen_len = EC_POINT_point2oct(group, G_tilde, POINT_CONVERSION_UNCOMPRESSED, gen_buf, sizeof(gen_buf), NULL);

    // 4. Build OSSL_PARAM list
    OSSL_PARAM_BLD *bld = OSSL_PARAM_BLD_new();

    int nidCurve = EC_GROUP_get_curve_name(group);
    //if(nidCurve == NID_undef)
    if(true)
    {
        if (!bld ||
            !OSSL_PARAM_BLD_push_utf8_string(bld, "field-type", "prime-field", 0) ||
            !OSSL_PARAM_BLD_push_BN(bld, "p", p) ||
            !OSSL_PARAM_BLD_push_BN(bld, "a", a) ||
            !OSSL_PARAM_BLD_push_BN(bld, "b", b) ||
            !OSSL_PARAM_BLD_push_BN(bld, "order", order) ||
            !OSSL_PARAM_BLD_push_BN(bld, "cofactor", cofactor) ||
            !OSSL_PARAM_BLD_push_octet_string(bld, "generator", gen_buf, gen_len))
        {
            fprintf(stderr, "Error building OSSL_PARAMs\n");
            return 1;
        }
    }
    else
    {
        OSSL_PARAM_BLD_push_utf8_string(bld, "group", OBJ_nid2sn(nidCurve), 0); // work-around
    }

    OSSL_PARAM *params = OSSL_PARAM_BLD_to_param(bld);

    // 5. Attempt Key Generation
    EVP_PKEY_CTX *ctx = EVP_PKEY_CTX_new_from_name(NULL, "EC", NULL);
    EVP_PKEY *key = NULL;

    printf("Starting keygen for curve with modified generator...\n");

    if (EVP_PKEY_keygen_init(ctx) <= 0) {
        print_errors();
    }

    if (EVP_PKEY_CTX_set_params(ctx, params) <= 0 || EVP_PKEY_generate(ctx, &key) <= 0) {
        fprintf(stderr, "\n--- KEY GENERATION FAILED ---\n");
        print_errors();
    } else {
        printf("SUCCESS: Key generated successfully.\n");
    }

    // Cleanup
    EVP_PKEY_free(key);
    EVP_PKEY_CTX_free(ctx);
    OSSL_PARAM_free(params);
    OSSL_PARAM_BLD_free(bld);
    BN_free(p); BN_free(a); BN_free(b);
    BN_free(order); BN_free(cofactor); BN_free(scalar);
    EC_POINT_free(G_tilde);
    EC_GROUP_free(group);

    return 0;
}
```

In 3.x, attempting to set a peer public key whose algorithm does not match the private key on an `EVP_PKEY_CTX` configured for derivation returns a typed error such as `EVP_R_OPERATION_NOT_SUPPORTED_FOR_THIS_KEYTYPE` or `EVP_R_DIFFERENT_KEY_TYPES`.

In 4.0.0, the same code path instead raises `EVP_R_INTERNAL_ERROR` (observed on some hosts at least):

```
error:030C0103:digital envelope routines:EVP_PKEY_derive_set_peer_ex:internal error:crypto/evp/exchange.c:427:
```

The behavior does not appear to be universal across all OpenSSL 4.0.0 builds, it reproduces at least on the following hosts (both using the nixpkgs `openssl_4_0` package):

- macOS arm64 (Apple Silicon), local build.
- Linux x86_64, GitHub Actions `ubuntu-24.04` runner.

This loss of information means we cannot distinguish "programmer error" from "real internal bug".

```c
#include <stdio.h>
#include <openssl/evp.h>
#include <openssl/err.h>

int main(void) {
    EVP_PKEY *priv = NULL, *pub = NULL;
    EVP_PKEY_CTX *gctx, *dctx;

    gctx = EVP_PKEY_CTX_new_from_name(NULL, "X448", NULL);
    EVP_PKEY_keygen_init(gctx);
    EVP_PKEY_keygen(gctx, &priv);
    EVP_PKEY_CTX_free(gctx);

    gctx = EVP_PKEY_CTX_new_from_name(NULL, "X25519", NULL);
    EVP_PKEY_keygen_init(gctx);
    EVP_PKEY_keygen(gctx, &pub);
    EVP_PKEY_CTX_free(gctx);

    dctx = EVP_PKEY_CTX_new(priv, NULL);
    EVP_PKEY_derive_init(dctx);
    if (EVP_PKEY_derive_set_peer(dctx, pub) <= 0)
        ERR_print_errors_fp(stderr);

    EVP_PKEY_CTX_free(dctx);
    EVP_PKEY_free(priv);
    EVP_PKEY_free(pub);
    return 0;
}
```

### Expected output (OpenSSL 3.x)

```
error:…:EVP routines::operation not supported for this keytype
```

### Actual output (OpenSSL 4.0.0)

```
error:030C0103:digital envelope routines:EVP_PKEY_derive_set_peer_ex:internal error:crypto/evp/exchange.c:427:
```

The same behavior is observed for multiple algorithm combinations that produced typed errors in 3.x:

- `X448` private + `X25519` peer
- `EC` (e.g. P-256) private + `X25519` peer
- `Ed25519` private + `Ed25519` peer (no derivation operation for this key type)

### OpenSSL Branch
3.0 and master, Other branches should have the same problem
### Description
With `X509_V_FLAG_PARTIAL_CHAIN` and `X509_V_FLAG_CRL_CHECK_ALL`, OpenSSL returns `X509_V_ERR_CRL_SIGNATURE_FAILURE`.
### Test Case
- Chain: A (EE) → B (Intermediate) → C (Root)
- Built chain with PARTIAL_CHAIN: [A, B] (2 certs, stops at intermediate)
- C1.crl issuer: "CN=Root CA C", signed by C
- Store contains: cert_c (Root CA C), cert_b (Intermediate CA B)
### Current Behavior
When verifying C1.crl for cert B:
- OpenSSL uses cert B from built chain as CRL issuer
- B is NOT the issuer of C1.crl (signed by C)
- Result: `CRL_SIGNATURE_FAILURE`
### Expected Behavior
When CRL issuer not in built chain, OpenSSL should either:
1. Return `UNABLE_TO_GET_CRL_ISSUER` (conservative approach)
2. Search X509_STORE for matching issuer (recommended approach)
### Proposed Solutions
**Solution 1: Return UNABLE_TO_GET_CRL_ISSUER**
- When CRL issuer not found in built chain
- Immediately return `X509_V_ERR_UNABLE_TO_GET_CRL_ISSUER`
- No signature verification attempt with wrong issuer
- Conservative, clear error indication

**Solution 2: Search store for CRL issuer (Recommended)**
- When CRL issuer not found in built chain
- Search X509_STORE for matching issuer certificate
- If found → verify CRL signature with correct issuer
- If not found in store → return `UNABLE_TO_GET_CRL_ISSUER`
- Aligns with PARTIAL_CHAIN semantics (store certs are valid trust anchors)
### Root Cause
CRL verification only searches the built chain for issuer, not the X509_STORE. With PARTIAL_CHAIN, the chain is incomplete and may not contain CRL issuers that exist in the store.

