X509 *load_cert_from_mem(const char *pem_data)
{
    BIO *bio = BIO_new_mem_buf(pem_data, -1);
    if (bio == NULL) {
        fprintf(stderr, "BIO_new_mem_buf failed\n");
        return NULL;
    }
    X509 *cert = PEM_read_bio_X509(bio, NULL, NULL, NULL);
    BIO_free(bio);
    return cert;
}

X509_CRL *load_crl_from_mem(const char *pem_data)
{
    BIO *bio = BIO_new_mem_buf(pem_data, -1);
    if (bio == NULL) {
        fprintf(stderr, "BIO_new_mem_buf failed\n");
        return NULL;
    }
    X509_CRL *crl = PEM_read_bio_X509_CRL(bio, NULL, NULL, NULL);
    BIO_free(bio);
    return crl;
}

int verify_cert_with_chain(X509 *cert, STACK_OF(X509) *chain, X509_STORE *store)
{
    X509_STORE_CTX *ctx = X509_STORE_CTX_new();
    if (ctx == NULL) {
        fprintf(stderr, "X509_STORE_CTX_new failed\n");
        return -1;
    }

    X509_STORE_CTX_init(ctx, store, cert, chain);
    X509_STORE_CTX_set_flags(ctx, X509_V_FLAG_NO_CHECK_TIME);
    X509_STORE_CTX_set_flags(ctx, X509_V_FLAG_PARTIAL_CHAIN);

    int ret = X509_verify_cert(ctx);
    int err = X509_STORE_CTX_get_error(ctx);

    if (ret != 1) {
        fprintf(stderr, "Verification failed: %s (error code: %d)\n",
                X509_verify_cert_error_string(err), err);
        if (err == X509_V_ERR_CERT_REVOKED) {
            fprintf(stderr, "  -> Certificate has been revoked!\n");
        }
    }

    STACK_OF(X509) *built_chain = X509_STORE_CTX_get1_chain(ctx);
    printf("Built chain: %d certificates\n", sk_X509_num(built_chain));
    for (int i = 0; i < sk_X509_num(built_chain); i++) {
        X509 *c = sk_X509_value(built_chain, i);
        char *subject = X509_NAME_oneline(X509_get_subject_name(c), NULL, 0);
        printf("  [%d] %s\n", i, subject);
        OPENSSL_free(subject);
    }
    sk_X509_pop_free(built_chain, X509_free);

    X509_STORE_CTX_free(ctx);
    return ret;
}

int main()
{
    OpenSSL_add_all_algorithms();
    ERR_load_crypto_strings();

    X509 *cert_a = load_cert_from_mem(cert_a_pem);
    if (cert_a == NULL) {
        fprintf(stderr, "Failed to load Certificate A\n");
        return -1;
    }

    X509 *cert_b = load_cert_from_mem(cert_b_pem);
    if (cert_b == NULL) {
        fprintf(stderr, "Failed to load Certificate B\n");
        X509_free(cert_a);
        return -1;
    }

    X509 *cert_c = load_cert_from_mem(cert_c_pem);
    if (cert_c == NULL) {
        fprintf(stderr, "Failed to load Certificate C\n");
        X509_free(cert_a);
        X509_free(cert_b);
        return -1;
    }

    X509_CRL *crl_b = load_crl_from_mem(crl_b_pem);
    if (crl_b == NULL) {
        fprintf(stderr, "Failed to load CRL from B\n");
        return -1;
    }

    X509_CRL *crl_c = load_crl_from_mem(crl_c_pem);
    if (crl_c == NULL) {
        fprintf(stderr, "Failed to load CRL from C\n");
