The SLH-DSA implementation in OpenSSL 4.0.0, I found a logic bug in slh_dsa_sign() that causes cryptographically sensitive randomness (the FIPS 205 addrnd signing nonce) to persist on the stack after every EVP_PKEY_sign() call in the default signing path.

By itself this doesn't compromise the secret key or enable signature forgery. However if it gets chained with a memory disclosure primitive like a separate bug, a core dump, swap file or debugger access, the leaked stack data directly reveals the cryptographic nonces and breaks the privacy property of randomized signing.

For comparison the sibling ML-DSA provider implements the exact same control structure but uses the correct condition. This looks like a regression from that established design.

Root Cause
The issue is in providers/implementations/signature/slh_dsa_sig.c around lines 244-245.

```
// ... setup code ...
    if (sig != NULL) {
        if (ctx->add_random_len != 0) {
            opt_rand = ctx->add_random; 
        } else if (ctx->deterministic == 0) {
            n = ossl_slh_dsa_key_get_n(ctx->key);
            if (RAND_priv_bytes_ex(ctx->libctx, add_rand, n, 0) <= 0) 
                return 0;
            opt_rand = add_rand; 
        }
    }

    ret = ossl_slh_dsa_sign(ctx->hash_ctx, msg, msg_len,
        ctx->context_string, ctx->context_string_len,
        opt_rand, ctx->msg_encode,
        sig, siglen, sigsize);

    if (opt_rand != add_rand)                  // BUG: inverted condition
        OPENSSL_cleanse(opt_rand, n);          // BUG: wrong target/size
    return ret;
}
```

In the normal randomized signing path, opt_rand points to the add_rand stack buffer. Because the condition checks opt_rand != add_rand, it evaluates to FALSE and the cleanse is completely skipped.

This creates three failure cases depending on execution:

Normal random signing: opt_rand points to the stack. Cleanse is skipped. The nonce leaks.

Test entropy override: opt_rand points to the heap. Condition is TRUE but n is still 0, resulting in a no-op cleanse.

Deterministic signing: opt_rand is NULL. Condition is TRUE, resulting in OPENSSL_cleanse(NULL, 0).

Impact

Leaking addrnd does not reveal the private key but it does break randomized-signing unlinkability. If an attacker recovers these stack bytes from crash dumps or a separate uninitialized memory read, they can correlate signatures to prove they came from the same signing session or key. It can also amplify side-channel attacks by revealing the exact inputs to internal hash operations.

Additionally this is a strict FIPS compliance failure for organizations in regulated environments like finance, healthcare or government. FIPS 140-3 requires sensitive security parameters (including approved RNG nonces) to be zeroized when no longer in use.

Proposed Fix
The fix is a simple one-line change to match the logic already used in ml_dsa_sig.c. We need to flip the operator and ensure we always cleanse the actual stack buffer using a compile-time size.

```
--- a/providers/implementations/signature/slh_dsa_sig.c
+++ b/providers/implementations/signature/slh_dsa_sig.c
@@ -241,8 +241,8 @@ static int slh_dsa_sign(void *vctx, unsigned char *sig, size_t *siglen,
      ret = ossl_slh_dsa_sign(ctx->hash_ctx, msg, msg_len,
          ctx->context_string, ctx->context_string_len,
          opt_rand, ctx->msg_encode,
          sig, siglen, sigsize);
-    if (opt_rand != add_rand)
-        OPENSSL_cleanse(opt_rand, n);
+    if (opt_rand == add_rand)
+        OPENSSL_cleanse(add_rand, sizeof(add_rand));
      return ret;
  }
```

Proof of Concept
I wrote a standalone reproducer that mirrors the exact control flow and stack layout of slh_dsa_sign() to make the memory leak highly visible using a dummy magic byte.

```
/*
 * PoC: SLH-DSA Stack Nonce Leak
 * Compile: gcc -O0 -fno-stack-protector -o slh_dsa_poc slh_dsa_poc.c
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define SLH_DSA_MAX_ADD_RANDOM_LEN 32
#define MAGIC_BYTE 0xA5

typedef struct {
    uint8_t add_random[SLH_DSA_MAX_ADD_RANDOM_LEN];
    size_t  add_random_len;
    int     deterministic;
} FakeCtx;

static size_t fake_get_n(void) { return 32; }

static int fake_rand_bytes(uint8_t *p, size_t n) {
    for (size_t i = 0; i < n; i++) p[i] = MAGIC_BYTE;
    return 1;
}

static void fake_slh_sign(const uint8_t *opt_rand, size_t n) {
    volatile uint8_t sink = 0;
    if (opt_rand) for (size_t i = 0; i < n; i++) sink ^= opt_rand[i];
    (void)sink;
}

/* OpenSSL 4.0.0 buggy behavior */
__attribute__((noinline))
static int buggy_slh_dsa_sign(FakeCtx *ctx) {
    uint8_t  add_rand[SLH_DSA_MAX_ADD_RANDOM_LEN];
    uint8_t *opt_rand = NULL;
    size_t   n = 0;

    if (ctx->add_random_len != 0) {
        opt_rand = ctx->add_random;
    } else if (ctx->deterministic == 0) {
        n = fake_get_n();
        if (fake_rand_bytes(add_rand, n) <= 0) return 0;
        opt_rand = add_rand;
    }
    fake_slh_sign(opt_rand, n);

    if (opt_rand != add_rand)
        memset(opt_rand, 0, n);
    return 1;
}

/* ML-DSA style fixed behavior */
__attribute__((noinline))
static int fixed_slh_dsa_sign(FakeCtx *ctx) {
    uint8_t  add_rand[SLH_DSA_MAX_ADD_RANDOM_LEN];
    uint8_t *opt_rand = NULL;
    size_t   n = 0;

    if (ctx->add_random_len != 0) {
        opt_rand = ctx->add_random;
    } else if (ctx->deterministic == 0) {
        n = fake_get_n();
        if (fake_rand_bytes(add_rand, n) <= 0) return 0;
        opt_rand = add_rand;
    }
    fake_slh_sign(opt_rand, n);

    if (opt_rand == add_rand)
        memset(add_rand, 0, sizeof(add_rand));
    return 1;
}

__attribute__((noinline))
static int probe(FakeCtx *ctx, const char *label) {
    uint8_t  probe_buf[SLH_DSA_MAX_ADD_RANDOM_LEN];
    uint8_t *dummy_ptr = NULL;
    size_t   n_dummy = 0;

    int hits = 0;
    for (size_t i = 0; i < sizeof(probe_buf); i++)
        if (probe_buf[i] == MAGIC_BYTE) hits++;

    printf("  [probe after %-24s] stack buffer = ", label);
    for (size_t i = 0; i < sizeof(probe_buf); i++)
        printf("%02x", probe_buf[i]);
    printf("  (MAGIC bytes: %d/%zu)\n", hits, sizeof(probe_buf));

    (void)ctx; (void)dummy_ptr; (void)n_dummy;
    return hits;
}

int main(void) {
    FakeCtx ctx = { .add_random_len = 0, .deterministic = 0 };

    printf("=== SLH-DSA Stack Nonce Leak PoC ===\n");
    printf("[A] BUGGY version (current OpenSSL 4.0.0):\n");
    buggy_slh_dsa_sign(&ctx);
    int buggy_hits = probe(&ctx, "buggy_slh_dsa_sign");

    printf("\n[B] FIXED version:\n");
    fixed_slh_dsa_sign(&ctx);
    int fixed_hits = probe(&ctx, "fixed_slh_dsa_sign");

    printf("\n=== RESULT ===\n");
    if (buggy_hits > fixed_hits) {
        printf("VULN CONFIRMED: buggy path left %d magic bytes on the stack\n", buggy_hits);
    }
    return 0;
}
